static int draw_legend(AVFilterContext *ctx, uint64_t samples)
{
    ShowSpectrumContext *s = ctx->priv;
    AVFilterLink *inlink = ctx->inputs[0];
    AVFilterLink *outlink = ctx->outputs[0];
    int ch, y, x = 0, sz = s->orientation == VERTICAL ? s->w : s->h;
    int multi = (s->mode == SEPARATE && s->color_mode == CHANNEL);
    float spp = samples / (float)sz;
    char *text;
    uint8_t *dst;
    char chlayout_str[128];

    av_channel_layout_describe(&inlink->ch_layout, chlayout_str, sizeof(chlayout_str));

    text = av_asprintf("%d Hz | %s", inlink->sample_rate, chlayout_str);
    if (!text)
        return AVERROR(ENOMEM);

    drawtext(s->outpicref, 2, outlink->h - 10, "CREATED BY LIBAVFILTER", 0);
    drawtext(s->outpicref, outlink->w - 2 - strlen(text) * 10, outlink->h - 10, text, 0);
    av_freep(&text);
    if (s->stop) {
        text = av_asprintf("Zoom: %d Hz - %d Hz", s->start, s->stop);
        if (!text)
            return AVERROR(ENOMEM);
        drawtext(s->outpicref, outlink->w - 2 - strlen(text) * 10, 3, text, 0);
        av_freep(&text);
    }

    dst = s->outpicref->data[0] + (s->start_y - 1) * s->outpicref->linesize[0] + s->start_x - 1;
    for (x = 0; x < s->w + 1; x++)
        dst[x] = 200;
    dst = s->outpicref->data[0] + (s->start_y + s->h) * s->outpicref->linesize[0] + s->start_x - 1;
    for (x = 0; x < s->w + 1; x++)
        dst[x] = 200;
    for (y = 0; y < s->h + 2; y++) {
        dst = s->outpicref->data[0] + (y + s->start_y - 1) * s->outpicref->linesize[0];
        dst[s->start_x - 1] = 200;
        dst[s->start_x + s->w] = 200;
    }
    if (s->orientation == VERTICAL) {
        int h = s->mode == SEPARATE ? s->h / s->nb_display_channels : s->h;
        int hh = s->mode == SEPARATE ? -(s->h % s->nb_display_channels) + 1 : 1;
        for (ch = 0; ch < (s->mode == SEPARATE ? s->nb_display_channels : 1); ch++) {
            for (y = 0; y < h; y += 20) {
                dst = s->outpicref->data[0] + (s->start_y + h * (ch + 1) - y - hh) * s->outpicref->linesize[0];
                dst[s->start_x - 2] = 200;
                dst[s->start_x + s->w + 1] = 200;
            }
            for (y = 0; y < h; y += 40) {
                dst = s->outpicref->data[0] + (s->start_y + h * (ch + 1) - y - hh) * s->outpicref->linesize[0];
                dst[s->start_x - 3] = 200;
                dst[s->start_x + s->w + 2] = 200;
            }
            dst = s->outpicref->data[0] + (s->start_y - 2) * s->outpicref->linesize[0] + s->start_x;
            for (x = 0; x < s->w; x+=40)
                dst[x] = 200;
            dst = s->outpicref->data[0] + (s->start_y - 3) * s->outpicref->linesize[0] + s->start_x;
            for (x = 0; x < s->w; x+=80)
                dst[x] = 200;
            dst = s->outpicref->data[0] + (s->h + s->start_y + 1) * s->outpicref->linesize[0] + s->start_x;
            for (x = 0; x < s->w; x+=40) {
                dst[x] = 200;
            }
            dst = s->outpicref->data[0] + (s->h + s->start_y + 2) * s->outpicref->linesize[0] + s->start_x;
            for (x = 0; x < s->w; x+=80) {
                dst[x] = 200;
            }
            for (y = 0; y < h; y += 40) {
                float range = s->stop ? s->stop - s->start : inlink->sample_rate / 2;
                float hertz = get_hz(y, h, s->start, s->start + range, s->fscale);
                char *units;

                if (hertz == 0)
                    units = av_asprintf("DC");
                else
                    units = av_asprintf("%.2f", hertz);
                if (!units)
                    return AVERROR(ENOMEM);

                drawtext(s->outpicref, s->start_x - 8 * strlen(units) - 4, h * (ch + 1) + s->start_y - y - 4 - hh, units, 0);
                av_free(units);
            }
        }

        for (x = 0; x < s->w && s->single_pic; x+=80) {
            float seconds = x * spp / inlink->sample_rate;
            char *units = get_time(ctx, seconds, x);
            if (!units)
                return AVERROR(ENOMEM);

            drawtext(s->outpicref, s->start_x + x - 4 * strlen(units), s->h + s->start_y + 6, units, 0);
            drawtext(s->outpicref, s->start_x + x - 4 * strlen(units), s->start_y - 12, units, 0);
            av_free(units);
        }

        drawtext(s->outpicref, outlink->w / 2 - 4 * 4, outlink->h - s->start_y / 2, "TIME", 0);
        drawtext(s->outpicref, s->start_x / 7, outlink->h / 2 - 14 * 4, "FREQUENCY (Hz)", 1);
    } else {
        int w = s->mode == SEPARATE ? s->w / s->nb_display_channels : s->w;
        for (y = 0; y < s->h; y += 20) {
            dst = s->outpicref->data[0] + (s->start_y + y) * s->outpicref->linesize[0];
            dst[s->start_x - 2] = 200;
            dst[s->start_x + s->w + 1] = 200;
        }
        for (y = 0; y < s->h; y += 40) {
            dst = s->outpicref->data[0] + (s->start_y + y) * s->outpicref->linesize[0];
            dst[s->start_x - 3] = 200;
            dst[s->start_x + s->w + 2] = 200;
        }
        for (ch = 0; ch < (s->mode == SEPARATE ? s->nb_display_channels : 1); ch++) {
            dst = s->outpicref->data[0] + (s->start_y - 2) * s->outpicref->linesize[0] + s->start_x + w * ch;
            for (x = 0; x < w; x+=40)
                dst[x] = 200;
            dst = s->outpicref->data[0] + (s->start_y - 3) * s->outpicref->linesize[0] + s->start_x + w * ch;
            for (x = 0; x < w; x+=80)
                dst[x] = 200;
            dst = s->outpicref->data[0] + (s->h + s->start_y + 1) * s->outpicref->linesize[0] + s->start_x + w * ch;
            for (x = 0; x < w; x+=40) {
                dst[x] = 200;
            }
            dst = s->outpicref->data[0] + (s->h + s->start_y + 2) * s->outpicref->linesize[0] + s->start_x + w * ch;
            for (x = 0; x < w; x+=80) {
                dst[x] = 200;
            }
            for (x = 0; x < w - 79; x += 80) {
                float range = s->stop ? s->stop - s->start : inlink->sample_rate / 2;
                float hertz = get_hz(x, w, s->start, s->start + range, s->fscale);
                char *units;

                if (hertz == 0)
                    units = av_asprintf("DC");
                else
                    units = av_asprintf("%.2f", hertz);
                if (!units)
                    return AVERROR(ENOMEM);

                drawtext(s->outpicref, s->start_x - 4 * strlen(units) + x + w * ch, s->start_y - 12, units, 0);
                drawtext(s->outpicref, s->start_x - 4 * strlen(units) + x + w * ch, s->h + s->start_y + 6, units, 0);
                av_free(units);
            }
        }
        for (y = 0; y < s->h && s->single_pic; y+=40) {
            float seconds = y * spp / inlink->sample_rate;
            char *units = get_time(ctx, seconds, x);
            if (!units)
                return AVERROR(ENOMEM);

            drawtext(s->outpicref, s->start_x - 8 * strlen(units) - 4, s->start_y + y - 4, units, 0);

llm_input.function:
static int draw_legend(AVFilterContext *ctx, uint64_t samples)
{
    ShowSpectrumContext *s = ctx->priv;
    AVFilterLink *inlink = ctx->inputs[0];
    AVFilterLink *outlink = ctx->outputs[0];
    int ch, y, x = 0, sz = s->orientation == VERTICAL ? s->w : s->h;
    int multi = (s->mode == SEPARATE && s->color_mode == CHANNEL);
    float spp = samples / (float)sz;
    char *text;
    uint8_t *dst;
    char chlayout_str[128];

    av_channel_layout_describe(&inlink->ch_layout, chlayout_str, sizeof(chlayout_str));

    text = av_asprintf("%d Hz | %s", inlink->sample_rate, chlayout_str);
    if (!text)
        return AVERROR(ENOMEM);

    drawtext(s->outpicref, 2, outlink->h - 10, "CREATED BY LIBAVFILTER", 0);
    drawtext(s->outpicref, outlink->w - 2 - strlen(text) * 10, outlink->h - 10, text, 0);
    av_freep(&text);
    if (s->stop) {
        text = av_asprintf("Zoom: %d Hz - %d Hz", s->start, s->stop);
        if (!text)
            return AVERROR(ENOMEM);
        drawtext(s->outpicref, outlink->w - 2 - strlen(text) * 10, 3, text, 0);
        av_freep(&text);
    }

    dst = s->outpicref->data[0] + (s->start_y - 1) * s->outpicref->linesize[0] + s->start_x - 1;
    for (x = 0; x < s->w + 1; x++)
        dst[x] = 200;
    dst = s->outpicref->data[0] + (s->start_y + s->h) * s->outpicref->linesize[0] + s->start_x - 1;
    for (x = 0; x < s->w + 1; x++)
        dst[x] = 200;
    for (y = 0; y < s->h + 2; y++) {
        dst = s->outpicref->data[0] + (y + s->start_y - 1) * s->outpicref->linesize[0];
        dst[s->start_x - 1] = 200;
        dst[s->start_x + s->w] = 200;
    }
    if (s->orientation == VERTICAL) {
        int h = s->mode == SEPARATE ? s->h / s->nb_display_channels : s->h;
        int hh = s->mode == SEPARATE ? -(s->h % s->nb_display_channels) + 1 : 1;
        for (ch = 0; ch < (s->mode == SEPARATE ? s->nb_display_channels : 1); ch++) {
            for (y = 0; y < h; y += 20) {
                dst = s->outpicref->data[0] + (s->start_y + h * (ch + 1) - y - hh) * s->outpicref->linesize[0];
                dst[s->start_x - 2] = 200;
                dst[s->start_x + s->w + 1] = 200;
            }
            for (y = 0; y < h; y += 40) {
                dst = s->outpicref->data[0] + (s->start_y + h * (ch + 1) - y - hh) * s->outpicref->linesize[0];
                dst[s->start_x - 3] = 200;
                dst[s->start_x + s->w + 2] = 200;
            }
            dst = s->outpicref->data[0] + (s->start_y - 2) * s->outpicref->linesize[0] + s->start_x;
            for (x = 0; x < s->w; x+=40)
                dst[x] = 200;
            dst = s->outpicref->data[0] + (s->start_y - 3) * s->outpicref->linesize[0] + s->start_x;
            for (x = 0; x < s->w; x+=80)
                dst[x] = 200;
            dst = s->outpicref->data[0] + (s->h + s->start_y + 1) * s->outpicref->linesize[0] + s->start_x;
            for (x = 0; x < s->w; x+=40) {
                dst[x] = 200;
            }
            dst = s->outpicref->data[0] + (s->h + s->start_y + 2) * s->outpicref->linesize[0] + s->start_x;
            for (x = 0; x < s->w; x+=80) {
                dst[x] = 200;
            }
            for (y = 0; y < h; y += 40) {
                float range = s->stop ? s->stop - s->start : inlink->sample_rate / 2;
                float hertz = get_hz(y, h, s->start, s->start + range, s->fscale);
                char *units;

                if (hertz == 0)
                    units = av_asprintf("DC");
                else
                    units = av_asprintf("%.2f", hertz);
                if (!units)
                    return AVERROR(ENOMEM);

                drawtext(s->outpicref, s->start_x - 8 * strlen(units) - 4, h * (ch + 1) + s->start_y - y - 4 - hh, units, 0);
                av_free(units);
            }
        }

        for (x = 0; x < s->w && s->single_pic; x+=80) {
            float seconds = x * spp / inlink->sample_rate;
            char *units = get_time(ctx, seconds, x);
            if (!units)
                return AVERROR(ENOMEM);

            drawtext(s->outpicref, s->start_x + x - 4 * strlen(units), s->h + s->start_y + 6, units, 0);
            drawtext(s->outpicref, s->start_x + x - 4 * strlen(units), s->start_y - 12, units, 0);
            av_free(units);
        }

        drawtext(s->outpicref, outlink->w / 2 - 4 * 4, outlink->h - s->start_y / 2, "TIME", 0);
        drawtext(s->outpicref, s->start_x / 7, outlink->h / 2 - 14 * 4, "FREQUENCY (Hz)", 1);
    } else {
        int w = s->mode == SEPARATE ? s->w / s->nb_display_channels : s->w;
        for (y = 0; y < s->h; y += 20) {
            dst = s->outpicref->data[0] + (s->start_y + y) * s->outpicref->linesize[0];
            dst[s->start_x - 2] = 200;
            dst[s->start_x + s->w + 1] = 200;
        }
        for (y = 0; y < s->h; y += 40) {
            dst = s->outpicref->data[0] + (s->start_y + y) * s->outpicref->linesize[0];
            dst[s->start_x - 3] = 200;
            dst[s->start_x + s->w + 2] = 200;
        }
        for (ch = 0; ch < (s->mode == SEPARATE ? s->nb_display_channels : 1); ch++) {
            dst = s->outpicref->data[0] + (s->start_y - 2) * s->outpicref->linesize[0] + s->start_x + w * ch;
            for (x = 0; x < w; x+=40)
                dst[x] = 200;
            dst = s->outpicref->data[0] + (s->start_y - 3) * s->outpicref->linesize[0] + s->start_x + w * ch;
            for (x = 0; x < w; x+=80)
                dst[x] = 200;
            dst = s->outpicref->data[0] + (s->h + s->start_y + 1) * s->outpicref->linesize[0] + s->start_x + w * ch;
            for (x = 0; x < w; x+=40) {
                dst[x] = 200;
            }
            dst = s->outpicref->data[0] + (s->h + s->start_y + 2) * s->outpicref->linesize[0] + s->start_x + w * ch;
            for (x = 0; x < w; x+=80) {
                dst[x] = 200;
            }
            for (x = 0; x < w - 79; x += 80) {
                float range = s->stop ? s->stop - s->start : inlink->sample_rate / 2;
                float hertz = get_hz(x, w, s->start, s->start + range, s->fscale);
                char *units;

                if (hertz == 0)
                    units = av_asprintf("DC");
                else
                    units = av_asprintf("%.2f", hertz);
                if (!units)
                    return AVERROR(ENOMEM);

                drawtext(s->outpicref, s->start_x - 4 * strlen(units) + x + w * ch, s->start_y - 12, units, 0);
                drawtext(s->outpicref, s->start_x - 4 * strlen(units) + x + w * ch, s->h + s->start_y + 6, units, 0);
                av_free(units);
            }
        }
        for (y = 0; y < s->h && s->single_pic; y+=40) {
            float seconds = y * spp / inlink->sample_rate;
            char *units = get_time(ctx, seconds, x);
            if (!units)
                return AVERROR(ENOMEM);

            drawtext(s->outpicref, s->start_x - 8 * strlen(units) - 4, s->start_y + y - 4, units, 0);
            av_free(units);
        }
        drawtext(s->outpicref, s->start_x / 7, outlink->h / 2 - 4 * 4, "TIME", 1);
        drawtext(s->outpicref, outlink->w / 2 - 14 * 4, outlink->h - s->start_y / 2, "FREQUENCY (Hz)", 0);
    }

    for (ch = 0; ch < (multi ? s->nb_display_channels : 1); ch++) {
        int h = multi ? s->h / s->nb_display_channels : s->h;

        for (y = 0; y < h; y++) {
            float out[4] = { 0., 127.5, 127.5, 0.f};
            int chn;

            for (chn = 0; chn < (s->mode == SEPARATE ? 1 : s->nb_display_channels); chn++) {
                float yf, uf, vf;
                int channel = (multi) ? s->nb_display_channels - ch - 1 : chn;
                float lout[4];

                color_range(s, channel, &yf, &uf, &vf);
                pick_color(s, yf, uf, vf, y / (float)h, lout);
                out[0] += lout[0];
                out[1] += lout[1];
                out[2] += lout[2];
                out[3] += lout[3];
            }
            memset(s->outpicref->data[0]+(s->start_y + h * (ch + 1) - y - 1) * s->outpicref->linesize[0] + s->w + s->start_x + 20, av_clip_uint8(out[0]), 10);
            memset(s->outpicref->data[1]+(s->start_y + h * (ch + 1) - y - 1) * s->outpicref->linesize[1] + s->w + s->start_x + 20, av_clip_uint8(out[1]), 10);
            memset(s->outpicref->data[2]+(s->start_y + h * (ch + 1) - y - 1) * s->outpicref->linesize[2] + s->w + s->start_x + 20, av_clip_uint8(out[2]), 10);
            if (s->outpicref->data[3])
                memset(s->outpicref->data[3]+(s->start_y + h * (ch + 1) - y - 1) * s->outpicref->linesize[3] + s->w + s->start_x + 20, av_clip_uint8(out[3]), 10);
        }

        for (y = 0; ch == 0 && y < h + 5; y += 25) {
            const float a = av_clipf(1.f - y / (float)(h - 1), 0.f, 1.f);
            const float value = s->scale == LOG ? log10f(get_iscale(ctx, s->scale, a)) * 20.f : get_iscale(ctx, s->scale, a);
            char scale_fmt[32];

            snprintf(scale_fmt, sizeof(scale_fmt),
                     s->scale == LOG ? "%.0f" : "%.3f", value);
            drawtext(s->outpicref, s->w + s->start_x + 35, s->start_y + y - 3, scale_fmt, 0);
        }
    }

    if (s->scale == LOG)
        drawtext(s->outpicref, s->w + s->start_x + 22, s->start_y + s->h + 20, "dBFS", 0);

    return 0;
}

llm_input.code_slice:
static int sdp_write_media_attributes(char *buff, int size, const AVStream *st,
                                      int payload_type, AVFormatContext *fmt)
{
    char *config = NULL;
    const AVCodecParameters *p = st->codecpar;
    int ret = 0;

    switch (p->codec_id) {
    case AV_CODEC_ID_AV1:
        av_strlcatf(buff, size, "a=rtpmap:%d AV1/90000\r\n", payload_type);
        if (p->extradata_size) {
            ret = extradata2psets_av1(fmt, p, &config);
            if (ret < 0)
                return ret;
            av_strlcatf(buff, size, "a=fmtp:%d %s\r\n", payload_type, config);
        }
        break;
    case AV_CODEC_ID_DIRAC:
        av_strlcatf(buff, size, "a=rtpmap:%d VC2/90000\r\n", payload_type);
        break;
    case AV_CODEC_ID_H264: {
        int mode = 1;
        if (fmt && fmt->oformat && fmt->oformat->priv_class &&
            av_opt_flag_is_set(fmt->priv_data, "rtpflags", "h264_mode0"))
            mode = 0;
        if (p->extradata_size) {
            ret = extradata2psets(fmt, p, &config);
            if (ret < 0)
                return ret;
        }
        av_strlcatf(buff, size, "a=rtpmap:%d H264/90000\r\n"
                                "a=fmtp:%d packetization-mode=%d%s\r\n",
                                 payload_type,
                                 payload_type, mode, config ? config : "");
        break;
    }
    case AV_CODEC_ID_H261:
    {
        const char *pic_fmt = NULL;
        /* only QCIF and CIF are specified as supported in RFC 4587 */
        if (p->width == 176 && p->height == 144)
            pic_fmt = "QCIF=1";
        else if (p->width == 352 && p->height == 288)
            pic_fmt = "CIF=1";
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d H261/90000\r\n", payload_type);
        if (pic_fmt)
            av_strlcatf(buff, size, "a=fmtp:%d %s\r\n", payload_type, pic_fmt);
        break;
    }
    case AV_CODEC_ID_H263:
    case AV_CODEC_ID_H263P:
        /* a=framesize is required by 3GPP TS 26.234 (PSS). It
         * actually specifies the maximum video size, but we only know
         * the current size. This is required for playback on Android
         * stagefright and on Samsung bada. */
        if (!fmt || !fmt->oformat->priv_class ||
            !av_opt_flag_is_set(fmt->priv_data, "rtpflags", "rfc2190") ||
            p->codec_id == AV_CODEC_ID_H263P)
        av_strlcatf(buff, size, "a=rtpmap:%d H263-2000/90000\r\n"
                                "a=framesize:%d %d-%d\r\n",
                                payload_type,
                                payload_type, p->width, p->height);
        break;
    case AV_CODEC_ID_HEVC:
        if (p->extradata_size) {
            ret = extradata2psets_hevc(fmt, p, &config);
            if (ret < 0)
                return ret;
        }
        av_strlcatf(buff, size, "a=rtpmap:%d H265/90000\r\n", payload_type);
        if (config)
            av_strlcatf(buff, size, "a=fmtp:%d %s\r\n",
                                     payload_type, config);
        break;
    case AV_CODEC_ID_MPEG4:
        if (p->extradata_size) {
            ret = extradata2config(fmt, p, &config);
            if (ret < 0)
                return ret;
        }
        av_strlcatf(buff, size, "a=rtpmap:%d MP4V-ES/90000\r\n"
                                "a=fmtp:%d profile-level-id=1%s\r\n",
                                 payload_type,
                                 payload_type, config ? config : "");
        break;
    case AV_CODEC_ID_AAC:
        if (fmt && fmt->oformat && fmt->oformat->priv_class &&
            av_opt_flag_is_set(fmt->priv_data, "rtpflags", "latm")) {
            ret = latm_context2config(fmt, p, &config);
            if (ret < 0)
                return ret;
            av_strlcatf(buff, size, "a=rtpmap:%d MP4A-LATM/%d/%d\r\n"
                                    "a=fmtp:%d profile-level-id=%d;cpresent=0;config=%s\r\n",
                                     payload_type, p->sample_rate, p->ch_layout.nb_channels,
                                     payload_type, latm_context2profilelevel(p), config);
        } else {
            if (p->extradata_size) {
                ret = extradata2config(fmt, p, &config);
                if (ret < 0)
                    return ret;
            } else {
                /* FIXME: maybe we can forge config information based on the
                 *        codec parameters...
                 */
                av_log(fmt, AV_LOG_ERROR, "AAC with no global headers is currently not supported.\n");
                return AVERROR(ENOSYS);
            }
            av_strlcatf(buff, size, "a=rtpmap:%d MPEG4-GENERIC/%d/%d\r\n"
                                    "a=fmtp:%d profile-level-id=1;"
                                    "mode=AAC-hbr;sizelength=13;indexlength=3;"
                                    "indexdeltalength=3%s\r\n",
                                     payload_type, p->sample_rate, p->ch_layout.nb_channels,
                                     payload_type, config);
        }
        break;
    case AV_CODEC_ID_PCM_S16BE:
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d L16/%d/%d\r\n",
                                     payload_type,
                                     p->sample_rate, p->ch_layout.nb_channels);
        break;
    case AV_CODEC_ID_PCM_S24BE:
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d L24/%d/%d\r\n",
                                     payload_type,
                                     p->sample_rate, p->ch_layout.nb_channels);
        break;
    case AV_CODEC_ID_PCM_MULAW:
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d PCMU/%d/%d\r\n",
                                     payload_type,
                                     p->sample_rate, p->ch_layout.nb_channels);
        break;
    case AV_CODEC_ID_PCM_ALAW:
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d PCMA/%d/%d\r\n",
                                     payload_type,
                                     p->sample_rate, p->ch_layout.nb_channels);
        break;
    case AV_CODEC_ID_AMR_NB:
        av_strlcatf(buff, size, "a=rtpmap:%d AMR/%d/%d\r\n"
                                "a=fmtp:%d octet-align=1\r\n",
                                 payload_type, p->sample_rate, p->ch_layout.nb_channels,
                                 payload_type);
        break;
    case AV_CODEC_ID_AMR_WB:
        av_strlcatf(buff, size, "a=rtpmap:%d AMR-WB/%d/%d\r\n"
                                "a=fmtp:%d octet-align=1\r\n",
                                 payload_type, p->sample_rate, p->ch_layout.nb_channels,
                                 payload_type);
        break;
    case AV_CODEC_ID_VORBIS:
        if (p->extradata_size)
            ret = xiph_extradata2config(fmt, p, &config);
        else {
            av_log(fmt, AV_LOG_ERROR, "Vorbis configuration info missing\n");
            ret = AVERROR_INVALIDDATA;
        }
        if (ret < 0)
            return ret;

        av_strlcatf(buff, size, "a=rtpmap:%d vorbis/%d/%d\r\n"
                                "a=fmtp:%d configuration=%s\r\n",
                                payload_type, p->sample_rate, p->ch_layout.nb_channels,
                                payload_type, config);
        break;
    case AV_CODEC_ID_THEORA: {
        const char *pix_fmt;
        switch (p->format) {
        case AV_PIX_FMT_YUV420P:
            pix_fmt = "YCbCr-4:2:0";
            break;
        case AV_PIX_FMT_YUV422P:
            pix_fmt = "YCbCr-4:2:2";
            break;
        case AV_PIX_FMT_YUV444P:
            pix_fmt = "YCbCr-4:4:4";
            break;
        default:
            av_log(fmt, AV_LOG_ERROR, "Unsupported pixel format.\n");
            return AVERROR(ENOSYS);
        }

        if (p->extradata_size)
            ret = xiph_extradata2config(fmt, p, &config);
        else {
            av_log(fmt, AV_LOG_ERROR, "Theora configuration info missing\n");
            ret = AVERROR_INVALIDDATA;
        }
        if (ret < 0)
            return ret;

        av_strlcatf(buff, size, "a=rtpmap:%d theora/90000\r\n"
                                "a=fmtp:%d delivery-method=inline; "
                                "width=%d; height=%d; sampling=%s; "
                                "configuration=%s\r\n",
                                payload_type, payload_type,
                                p->width, p->height, pix_fmt, config);
        break;
    }
    case AV_CODEC_ID_BITPACKED:
    case AV_CODEC_ID_RAWVIDEO: {
        const char *pix_fmt;
        int bit_depth = 8;

        switch (p->format) {
        case AV_PIX_FMT_UYVY422:
            pix_fmt = "YCbCr-4:2:2";
            break;
        case AV_PIX_FMT_YUV422P10:
            pix_fmt = "YCbCr-4:2:2";
            bit_depth = 10;
            break;
        case AV_PIX_FMT_YUV420P:
            pix_fmt = "YCbCr-4:2:0";
            break;
        case AV_PIX_FMT_RGB24:
            pix_fmt = "RGB";
            break;
        case AV_PIX_FMT_BGR24:
            pix_fmt = "BGR";
            break;
        default:
            av_log(fmt, AV_LOG_ERROR, "Unsupported pixel format.\n");
            return AVERROR(ENOSYS);
        }

        av_strlcatf(buff, size, "a=rtpmap:%d raw/90000\r\n"
                                "a=fmtp:%d sampling=%s; "
                                "width=%d; height=%d; "
                                "depth=%d",
                                payload_type, payload_type,
                                pix_fmt, p->width, p->height, bit_depth);
        if (p->field_order != AV_FIELD_PROGRESSIVE)
            av_strlcatf(buff, size, "; interlace");
        av_strlcatf(buff, size, "\r\n");
        break;
    }

    case AV_CODEC_ID_VP8:
        av_strlcatf(buff, size, "a=rtpmap:%d VP8/90000\r\n",
                                 payload_type);
        break;
    case AV_CODEC_ID_VP9:
        av_strlcatf(buff, size, "a=rtpmap:%d VP9/90000\r\n",
                                 payload_type);
        break;
    case AV_CODEC_ID_MJPEG:
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d JPEG/90000\r\n",
                                     payload_type);
        break;
    case AV_CODEC_ID_ADPCM_G722:
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d G722/%d/%d\r\n",
                                     payload_type,
                                     8000, p->ch_layout.nb_channels);
        break;
    case AV_CODEC_ID_ADPCM_G726: {
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d AAL2-G726-%d/%d\r\n",
                                     payload_type,
                                     p->bits_per_coded_sample*8,
                                     p->sample_rate);
        break;
    }
    case AV_CODEC_ID_ADPCM_G726LE: {
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d G726-%d/%d\r\n",
                                     payload_type,
                                     p->bits_per_coded_sample*8,
                                     p->sample_rate);
        break;
    }
    case AV_CODEC_ID_ILBC:
        av_strlcatf(buff, size, "a=rtpmap:%d iLBC/%d\r\n"
                                "a=fmtp:%d mode=%d\r\n",
                                 payload_type, p->sample_rate,
                                 payload_type, p->block_align == 38 ? 20 : 30);
        break;
    case AV_CODEC_ID_SPEEX:
        av_strlcatf(buff, size, "a=rtpmap:%d speex/%d\r\n",
                                 payload_type, p->sample_rate);
        break;
    case AV_CODEC_ID_OPUS:
        /* The opus RTP draft says that all opus streams MUST be declared
           as stereo, to avoid negotiation failures. The actual number of
           channels can change on a packet-by-packet basis. The number of
           channels a receiver prefers to receive or a sender plans to send
           can be declared via fmtp parameters (both default to mono), but
           receivers MUST be able to receive and process stereo packets. */
        av_strlcatf(buff, size, "a=rtpmap:%d opus/48000/2\r\n",
                                 payload_type);
        if (p->ch_layout.nb_channels == 2) {
            av_strlcatf(buff, size, "a=fmtp:%d sprop-stereo=1\r\n",
                                     payload_type);
        }
        break;
    default:
        /* Nothing special to do here... */
        break;
    }

    av_free(config);

llm_input.function:
static int sdp_write_media_attributes(char *buff, int size, const AVStream *st,
                                      int payload_type, AVFormatContext *fmt)
{
    char *config = NULL;
    const AVCodecParameters *p = st->codecpar;
    int ret = 0;

    switch (p->codec_id) {
    case AV_CODEC_ID_AV1:
        av_strlcatf(buff, size, "a=rtpmap:%d AV1/90000\r\n", payload_type);
        if (p->extradata_size) {
            ret = extradata2psets_av1(fmt, p, &config);
            if (ret < 0)
                return ret;
            av_strlcatf(buff, size, "a=fmtp:%d %s\r\n", payload_type, config);
        }
        break;
    case AV_CODEC_ID_DIRAC:
        av_strlcatf(buff, size, "a=rtpmap:%d VC2/90000\r\n", payload_type);
        break;
    case AV_CODEC_ID_H264: {
        int mode = 1;
        if (fmt && fmt->oformat && fmt->oformat->priv_class &&
            av_opt_flag_is_set(fmt->priv_data, "rtpflags", "h264_mode0"))
            mode = 0;
        if (p->extradata_size) {
            ret = extradata2psets(fmt, p, &config);
            if (ret < 0)
                return ret;
        }
        av_strlcatf(buff, size, "a=rtpmap:%d H264/90000\r\n"
                                "a=fmtp:%d packetization-mode=%d%s\r\n",
                                 payload_type,
                                 payload_type, mode, config ? config : "");
        break;
    }
    case AV_CODEC_ID_H261:
    {
        const char *pic_fmt = NULL;
        /* only QCIF and CIF are specified as supported in RFC 4587 */
        if (p->width == 176 && p->height == 144)
            pic_fmt = "QCIF=1";
        else if (p->width == 352 && p->height == 288)
            pic_fmt = "CIF=1";
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d H261/90000\r\n", payload_type);
        if (pic_fmt)
            av_strlcatf(buff, size, "a=fmtp:%d %s\r\n", payload_type, pic_fmt);
        break;
    }
    case AV_CODEC_ID_H263:
    case AV_CODEC_ID_H263P:
        /* a=framesize is required by 3GPP TS 26.234 (PSS). It
         * actually specifies the maximum video size, but we only know
         * the current size. This is required for playback on Android
         * stagefright and on Samsung bada. */
        if (!fmt || !fmt->oformat->priv_class ||
            !av_opt_flag_is_set(fmt->priv_data, "rtpflags", "rfc2190") ||
            p->codec_id == AV_CODEC_ID_H263P)
        av_strlcatf(buff, size, "a=rtpmap:%d H263-2000/90000\r\n"
                                "a=framesize:%d %d-%d\r\n",
                                payload_type,
                                payload_type, p->width, p->height);
        break;
    case AV_CODEC_ID_HEVC:
        if (p->extradata_size) {
            ret = extradata2psets_hevc(fmt, p, &config);
            if (ret < 0)
                return ret;
        }
        av_strlcatf(buff, size, "a=rtpmap:%d H265/90000\r\n", payload_type);
        if (config)
            av_strlcatf(buff, size, "a=fmtp:%d %s\r\n",
                                     payload_type, config);
        break;
    case AV_CODEC_ID_MPEG4:
        if (p->extradata_size) {
            ret = extradata2config(fmt, p, &config);
            if (ret < 0)
                return ret;
        }
        av_strlcatf(buff, size, "a=rtpmap:%d MP4V-ES/90000\r\n"
                                "a=fmtp:%d profile-level-id=1%s\r\n",
                                 payload_type,
                                 payload_type, config ? config : "");
        break;
    case AV_CODEC_ID_AAC:
        if (fmt && fmt->oformat && fmt->oformat->priv_class &&
            av_opt_flag_is_set(fmt->priv_data, "rtpflags", "latm")) {
            ret = latm_context2config(fmt, p, &config);
            if (ret < 0)
                return ret;
            av_strlcatf(buff, size, "a=rtpmap:%d MP4A-LATM/%d/%d\r\n"
                                    "a=fmtp:%d profile-level-id=%d;cpresent=0;config=%s\r\n",
                                     payload_type, p->sample_rate, p->ch_layout.nb_channels,
                                     payload_type, latm_context2profilelevel(p), config);
        } else {
            if (p->extradata_size) {
                ret = extradata2config(fmt, p, &config);
                if (ret < 0)
                    return ret;
            } else {
                /* FIXME: maybe we can forge config information based on the
                 *        codec parameters...
                 */
                av_log(fmt, AV_LOG_ERROR, "AAC with no global headers is currently not supported.\n");
                return AVERROR(ENOSYS);
            }
            av_strlcatf(buff, size, "a=rtpmap:%d MPEG4-GENERIC/%d/%d\r\n"
                                    "a=fmtp:%d profile-level-id=1;"
                                    "mode=AAC-hbr;sizelength=13;indexlength=3;"
                                    "indexdeltalength=3%s\r\n",
                                     payload_type, p->sample_rate, p->ch_layout.nb_channels,
                                     payload_type, config);
        }
        break;
    case AV_CODEC_ID_PCM_S16BE:
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d L16/%d/%d\r\n",
                                     payload_type,
                                     p->sample_rate, p->ch_layout.nb_channels);
        break;
    case AV_CODEC_ID_PCM_S24BE:
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d L24/%d/%d\r\n",
                                     payload_type,
                                     p->sample_rate, p->ch_layout.nb_channels);
        break;
    case AV_CODEC_ID_PCM_MULAW:
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d PCMU/%d/%d\r\n",
                                     payload_type,
                                     p->sample_rate, p->ch_layout.nb_channels);
        break;
    case AV_CODEC_ID_PCM_ALAW:
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d PCMA/%d/%d\r\n",
                                     payload_type,
                                     p->sample_rate, p->ch_layout.nb_channels);
        break;
    case AV_CODEC_ID_AMR_NB:
        av_strlcatf(buff, size, "a=rtpmap:%d AMR/%d/%d\r\n"
                                "a=fmtp:%d octet-align=1\r\n",
                                 payload_type, p->sample_rate, p->ch_layout.nb_channels,
                                 payload_type);
        break;
    case AV_CODEC_ID_AMR_WB:
        av_strlcatf(buff, size, "a=rtpmap:%d AMR-WB/%d/%d\r\n"
                                "a=fmtp:%d octet-align=1\r\n",
                                 payload_type, p->sample_rate, p->ch_layout.nb_channels,
                                 payload_type);
        break;
    case AV_CODEC_ID_VORBIS:
        if (p->extradata_size)
            ret = xiph_extradata2config(fmt, p, &config);
        else {
            av_log(fmt, AV_LOG_ERROR, "Vorbis configuration info missing\n");
            ret = AVERROR_INVALIDDATA;
        }
        if (ret < 0)
            return ret;

        av_strlcatf(buff, size, "a=rtpmap:%d vorbis/%d/%d\r\n"
                                "a=fmtp:%d configuration=%s\r\n",
                                payload_type, p->sample_rate, p->ch_layout.nb_channels,
                                payload_type, config);
        break;
    case AV_CODEC_ID_THEORA: {
        const char *pix_fmt;
        switch (p->format) {
        case AV_PIX_FMT_YUV420P:
            pix_fmt = "YCbCr-4:2:0";
            break;
        case AV_PIX_FMT_YUV422P:
            pix_fmt = "YCbCr-4:2:2";
            break;
        case AV_PIX_FMT_YUV444P:
            pix_fmt = "YCbCr-4:4:4";
            break;
        default:
            av_log(fmt, AV_LOG_ERROR, "Unsupported pixel format.\n");
            return AVERROR(ENOSYS);
        }

        if (p->extradata_size)
            ret = xiph_extradata2config(fmt, p, &config);
        else {
            av_log(fmt, AV_LOG_ERROR, "Theora configuration info missing\n");
            ret = AVERROR_INVALIDDATA;
        }
        if (ret < 0)
            return ret;

        av_strlcatf(buff, size, "a=rtpmap:%d theora/90000\r\n"
                                "a=fmtp:%d delivery-method=inline; "
                                "width=%d; height=%d; sampling=%s; "
                                "configuration=%s\r\n",
                                payload_type, payload_type,
                                p->width, p->height, pix_fmt, config);
        break;
    }
    case AV_CODEC_ID_BITPACKED:
    case AV_CODEC_ID_RAWVIDEO: {
        const char *pix_fmt;
        int bit_depth = 8;

        switch (p->format) {
        case AV_PIX_FMT_UYVY422:
            pix_fmt = "YCbCr-4:2:2";
            break;
        case AV_PIX_FMT_YUV422P10:
            pix_fmt = "YCbCr-4:2:2";
            bit_depth = 10;
            break;
        case AV_PIX_FMT_YUV420P:
            pix_fmt = "YCbCr-4:2:0";
            break;
        case AV_PIX_FMT_RGB24:
            pix_fmt = "RGB";
            break;
        case AV_PIX_FMT_BGR24:
            pix_fmt = "BGR";
            break;
        default:
            av_log(fmt, AV_LOG_ERROR, "Unsupported pixel format.\n");
            return AVERROR(ENOSYS);
        }

        av_strlcatf(buff, size, "a=rtpmap:%d raw/90000\r\n"
                                "a=fmtp:%d sampling=%s; "
                                "width=%d; height=%d; "
                                "depth=%d",
                                payload_type, payload_type,
                                pix_fmt, p->width, p->height, bit_depth);
        if (p->field_order != AV_FIELD_PROGRESSIVE)
            av_strlcatf(buff, size, "; interlace");
        av_strlcatf(buff, size, "\r\n");
        break;
    }

    case AV_CODEC_ID_VP8:
        av_strlcatf(buff, size, "a=rtpmap:%d VP8/90000\r\n",
                                 payload_type);
        break;
    case AV_CODEC_ID_VP9:
        av_strlcatf(buff, size, "a=rtpmap:%d VP9/90000\r\n",
                                 payload_type);
        break;
    case AV_CODEC_ID_MJPEG:
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d JPEG/90000\r\n",
                                     payload_type);
        break;
    case AV_CODEC_ID_ADPCM_G722:
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d G722/%d/%d\r\n",
                                     payload_type,
                                     8000, p->ch_layout.nb_channels);
        break;
    case AV_CODEC_ID_ADPCM_G726: {
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d AAL2-G726-%d/%d\r\n",
                                     payload_type,
                                     p->bits_per_coded_sample*8,
                                     p->sample_rate);
        break;
    }
    case AV_CODEC_ID_ADPCM_G726LE: {
        if (payload_type >= RTP_PT_PRIVATE)
            av_strlcatf(buff, size, "a=rtpmap:%d G726-%d/%d\r\n",
                                     payload_type,
                                     p->bits_per_coded_sample*8,
                                     p->sample_rate);
        break;
    }
    case AV_CODEC_ID_ILBC:
        av_strlcatf(buff, size, "a=rtpmap:%d iLBC/%d\r\n"
                                "a=fmtp:%d mode=%d\r\n",
                                 payload_type, p->sample_rate,
                                 payload_type, p->block_align == 38 ? 20 : 30);
        break;
    case AV_CODEC_ID_SPEEX:
        av_strlcatf(buff, size, "a=rtpmap:%d speex/%d\r\n",
                                 payload_type, p->sample_rate);
        break;
    case AV_CODEC_ID_OPUS:
        /* The opus RTP draft says that all opus streams MUST be declared
           as stereo, to avoid negotiation failures. The actual number of
           channels can change on a packet-by-packet basis. The number of
           channels a receiver prefers to receive or a sender plans to send
           can be declared via fmtp parameters (both default to mono), but
           receivers MUST be able to receive and process stereo packets. */
        av_strlcatf(buff, size, "a=rtpmap:%d opus/48000/2\r\n",
                                 payload_type);
        if (p->ch_layout.nb_channels == 2) {
            av_strlcatf(buff, size, "a=fmtp:%d sprop-stereo=1\r\n",
                                     payload_type);
        }
        break;
    default:
        /* Nothing special to do here... */
        break;
    }

    av_free(config);

    return 0;
}
